sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;

    g_form.clearOptions('servicenow_status');
    g_form.setValue('servicenow_status', '');

    if (!newValue) return;

    g_form.addOption('servicenow_status', '', '-- Select Status --');

    var ga = new GlideAjax('PulseCategoryAjax'); // or PulseStatusAjax if you made a new one
    ga.addParam('sysparm_name', 'getStates');
    ga.addParam('sysparm_table', newValue);

    ga.getXMLAnswer(function (answer) {
        if (!answer) return;

        var states = JSON.parse(answer);
        for (var i = 0; i < states.length; i++) {
            g_form.addOption('servicenow_status', states[i].value, states[i].label);
        }
    });
}
